Part.Source:
//Restricao no cliente For Each Order EmpCod, PesCod Where EmpCod = &EmpCod Where PesCod = &PedCliCod
Do CAse CAse not PesEnvSpc.IsNull() and not PesEnvSpc.IsEmpty() &SdtCreditos.RestricaoMensagem = 'ENVIADO AO SPC!' &SdtCreditos.IsTemRestricao = true Case PesVenAprz = 'N' &SdtCreditos.RestricaoMensagem = 'RESTRIÇÃO VENDA À PRAZO!' &SdtCreditos.IsTemRestricao = true EndCase
&sdtCreditos.PesCliCrd = PesCliCrd
Exit EndFor
//SOMA DUPLICATAS VENCIDA RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon038_QtdDiasDupVencida, &CfgVlr) &Dias = val(&CfgVlr) &BaseData = serverdate() - &Dias
//CLIENTE COM DEBITOS For Each Order EmpCod, CreCliCod, CreRecPag Where EmpCod = &EmpCod Where CreRecPag = ReceberPagar.Receber Where CreSts <> Status_Duplicata.CANCELADA Where CreFrpPgtoTip <> TipoDuplicata.CARTAOD and CreFrpPgtoTip <> TipoDuplicata.CARTAOC Where CreCliCod = &PedCliCod Where CreDtaVct < &BaseData Where CreVlrSdo > 0 &SdtCreditos.VencidasMensagem = 'DUPLICATAS VENCIDAS!' &SdtCreditos.IsTemVencidas = true
exit EndFor
if &sdtCreditos.PesCliCrd > 0 //SOMA DUPLICATAS EM ABERTO For Each Order EmpCod, CreCliCod, CreRecPag Where EmpCod = &EmpCod Where CreRecPag = ReceberPagar.Receber Where CreSts <> Status_Duplicata.CANCELADA Where CreFrpPgtoTip <> TipoDuplicata.CARTAOD and CreFrpPgtoTip <> TipoDuplicata.CARTAOC Where CreCliCod = &PedCliCod Where CreVlrSdo > 0
&sdtCreditos.PesCliCrdUti += CreVlrSdo EndFor
//CALCULA SALDO DISPONIVEL &SdtCreditos.PesCliSdo = &sdtCreditos.PesCliCrd - &sdtCreditos.PesCliCrdUti
if &SdtCreditos.PesCliSdo <= 0 &SdtCreditos.LimiteMensagem = 'LIMITE ATINGIDO!' &SdtCreditos.IsLimiteAtingido = true Endif Endif
//PEGA OS VINCULOS retornaVinculos.Call(&EmpCod, &PedCliCod, &sdtVinculos)
For &sdtVinculosItem in &sdtVinculos If &sdtVinculosItem.PesCod <> &PedCliCod &CollPedCliCod.Add(&sdtVinculosItem.PesCod) &SdtCreditos.isTemVinculos = true if &SdtCreditos.VinculosMensagem.IsEmpty() &SdtCreditos.VinculosMensagem = 'CLIENTES VINCULADOS' EndIf
if &sdtVinculosItem.PesIsMat = true &SdtCreditos.VinculosMensagem += NewLine() + '[MATRIZ] ' + trim(str(&sdtVinculosItem.PesCod)) + ' - ' + trim(&sdtVinculosItem.PesRaz) Else &SdtCreditos.VinculosMensagem += NewLine() + '[VINCULO] ' + trim(str(&sdtVinculosItem.PesCod)) + ' - ' + trim(&sdtVinculosItem.PesRaz) Endif EndIF EndFor
//VERIFICA RESTRICOES VINCULOS For Each Order EmpCod, PesCod Where EmpCod = &EmpCod Where PesCod in &CollPedCliCod
Do CAse CAse not PesEnvSpc.IsNull() and not PesEnvSpc.IsEmpty() &SdtCreditos.IsTemRestricaoVinculos = true Exit Case PesVenAprz = 'N' &SdtCreditos.IsTemRestricaoVinculos = true Exit EndCase EndFor
if &sdtCreditos.IsTemRestricaoVinculos = false //nao tem restricao nos vinculos, veja os debitos. //VERIFICA DUPLICATAS VENCIDAS VINCULOS For Each Order EmpCod, CreCliCod, CreRecPag Where EmpCod = &EmpCod Where CreRecPag = ReceberPagar.Receber Where CreSts <> Status_Duplicata.CANCELADA Where CreFrpPgtoTip <> TipoDuplicata.CARTAOD and CreFrpPgtoTip <> TipoDuplicata.CARTAOC Where CreCliCod in &CollPedCliCod Where CreDtaVct < &BaseData Where CreVlrSdo > 0 &SdtCreditos.IsTemRestricaoVinculos = true
exit EndFor Endif
